function solve(n: number, edges: number[][]): number {
    // Build adjacency list
    const graph: number[][] = Array.from({ length: n }, () => []);
    for (const [u, v, w] => edges) {
        graph[u].push([v, w]);
    }

    // Dijkstra's algorithm with state tracking
    // Each state is (node, hasSwitchUsed)
    // hasSwitchUsed is a boolean indicating whether the switch at this node has been used
    // We use a priority queue to process states in order of increasing cost
    const pq = new PriorityQueue<[number, boolean, number]>([0, false, 0]);
    const dist = Array.from({ length: n }, () => Array(2).fill(Infinity));
    dist[0][false] = 0;

    while (!pq.isEmpty()) {
        const [node, hasSwitchUsed, cost] = pq.poll();

        // If we've reached the destination
        if (node === n - 1) {
            return cost;
        }

        // If we've already found a better path, skip
        if (cost > dist[node][hasSwitchUsed]) {
            continue;
        }

        // Explore neighbors
        for (const [v, w] of graph[node]) {
            // Regular edge
            const newCost = cost + w;
            if (newCost < dist[v][hasSwitchUsed]) {
                dist[v][hasSwitchUsed] = newCost;
                pq.push([v, hasSwitchUsed, newCost]);
            }

            // Reverse edge (if switch hasn't been used)
            if (!hasSwitchUsed) {
                const reversedCost = cost + 2 * w;
                if (reversedCost < dist[v][true]) {
                    dist[v][true] = reversedCost;
                    pq.push([v, true, reversedCost]);
                }
            }
        }
    }

    // If we can't reach the destination
    return -1;
}

// Priority queue implementation
class PriorityQueue<T> {
    private heap: T[];
    private comparator: (a: T, b: T) => number;

    constructor(private initial: T[] = []) {
        this.heap = initial;
        this.comparator = (a, b) => {
            return a[2] - b[2];
        };
        this.buildHeap();
    }

    private buildHeap(): void {
        for (let i = Math.floor(this.heap.length / 2) - 1; i >= 0; i--) {
            this.heapify(i);
        }
    }

    private heapify(i: number): void {
        let smallest = i;
        const left = 2 * i + 1;
        const right = 2 * i + 2;

        if (left < this.heap.length && this.comparator(this.heap[left], this.heap[smallest]) < 0) {
            smallest = left;
        }

        if (right < this.heap.length && this.comparator(this.heap[right], this.heap[smallest]) < 0) {
            smallest = right;
        }

        if (smallest !== i) {
            [this.heap[i], this.heap[smallest]] = [this.heap[smallest], this.heap[i]];
            this.heapify(smallest);
        }
    }

    public poll(): T {
        if (this.heap.length === 0) return undefined as any;
        const result = this.heap[0];
        this.heap[0] = this.heap[this.heap.length - 1];
        this.heap.pop();
        this.heapify(0);
        return result;
    }

    public push(value: T): void {
        this.heap.push(value);
        let i = this.heap.length - 1;
        while (i > 0) {
            const parent = Math.floor((i - 1) / 2);
            if (this.comparator(this.heap[i], this.heap[parent]) >= 0) {
                [this.heap[i], this.heap[parent]] = [this.heap[parent], this.heap[i]];
                i = parent;
            } else {
                break;
            }
        }
    }

    public isEmpty(): boolean {
        return this.heap.length === 0;
    }
}

